const metaData = $('Meta Ads Insights').first().json;
const metaCampaigns = metaData.data || [];
const gadsRows = $('Google Ads Metrics').first().json?.results || [];

const today = new Date().toLocaleDateString('en-IN', {day:'2-digit',month:'short',year:'numeric'});

const metaSpend = metaCampaigns.reduce((s,c) => s + parseFloat(c.spend||0), 0);
const metaImpr = metaCampaigns.reduce((s,c) => s + parseInt(c.impressions||0), 0);
const metaClicks = metaCampaigns.reduce((s,c) => s + parseInt(c.clicks||0), 0);

const gadsSpend = gadsRows.reduce((s,r) => s + (parseInt(r.metrics?.cost_micros||0)/1e6), 0);
const gadsImpr = gadsRows.reduce((s,r) => s + parseInt(r.metrics?.impressions||0), 0);

const metaLines = metaCampaigns.length > 0
  ? metaCampaigns.map(c =>
      `• ${c.campaign_name}: ₹${parseFloat(c.spend).toFixed(0)} | ${parseInt(c.impressions).toLocaleString()} impr | ${c.clicks} clicks`
    ).join('\n')
  : '• No active campaigns';

const gadsLines = gadsRows.length > 0
  ? gadsRows.map(r =>
      `• ${r.campaign?.name}: ₹${(parseInt(r.metrics?.cost_micros||0)/1e6).toFixed(0)} | ${parseInt(r.metrics?.impressions||0).toLocaleString()} impr`
    ).join('\n')
  : '• No data';

const total = metaSpend + gadsSpend;
const msg = `*Nubo Ads Report — ${today}*

*Meta Ads*
${metaLines}
Spend: ₹${metaSpend.toFixed(0)} | Impressions: ${metaImpr.toLocaleString()} | Clicks: ${metaClicks}

*Google Ads (PMax)*
${gadsLines}
Spend: ₹${gadsSpend.toFixed(0)} | Impressions: ${gadsImpr.toLocaleString()}

*Total today: ₹${total.toFixed(0)}*`;

return [{ json: { message: msg } }];
